 1	import React, { FC, useState } from 'react';
 2	
 3	import HyperConvergedModel from '@kubevirt-ui/kubevirt-api/console/models/HyperConvergedModel';
 4	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 5	import { FEATURE_HCO_PERSISTENT_RESERVATION } from '@kubevirt-utils/hooks/useFeatures/constants';
 6	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 7	import { HyperConverged } from '@kubevirt-utils/hooks/useHyperConvergeConfiguration';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
10	import {
11	  Alert,
12	  AlertVariant,
13	  PopoverPosition,
14	  Split,
15	  SplitItem,
16	  Switch,
17	} from '@patternfly/react-core';
18	
19	import ExpandSection from '../../../ExpandSection/ExpandSection';
20	
21	type PersistentReservationSectionProps = {
22	  hyperConvergeConfiguration: [hyperConvergeConfig: HyperConverged, loaded: boolean, error: Error];
23	};
24	
25	const PersistentReservationSection: FC<PersistentReservationSectionProps> = ({
26	  hyperConvergeConfiguration,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	  const [hyperConverge, hyperLoaded] = hyperConvergeConfiguration;
30	  const persistentReservation = Boolean(hyperConverge?.spec?.featureGates?.persistentReservation);
31	
32	  const [error, setError] = useState<Error>(null);
33	  const [isLoading, setIsLoading] = useState<boolean>(false);
34	  const { toggleFeature } = useFeatures(FEATURE_HCO_PERSISTENT_RESERVATION);
35	
36	  const onChange = async (checked: boolean) => {
37	    setIsLoading(true);
38	    try {
39	      await k8sPatch<HyperConverged>({
40	        data: [
41	          {
42	            op: 'replace',
43	            path: `/spec/featureGates/persistentReservation`,
44	            value: checked,
45	          },
46	        ],
47	        model: HyperConvergedModel,
48	        resource: hyperConverge,
49	      });
50	
51	      await toggleFeature(checked);
52	      setIsLoading(false);
53	    } catch (err) {
54	      setError(err.message);
55	    }
56	  };
57	
58	  return (
59	    <ExpandSection toggleText={t('SCSI persistent reservation')}>
60	      <Split>
61	        <SplitItem isFilled>
62	          {t('Enable persistent reservation')}{' '}
63	          <HelpTextIcon
64	            bodyContent={t(
65	              'The SCSI reservation for disk makes the disk attached to the VirtualMachine as a SCSI LUN. This option should only be used for cluster-aware applications',
66	            )}
67	            position={PopoverPosition.bottom}
68	          />
69	        </SplitItem>
70	        {hyperLoaded && (
71	          <SplitItem>
72	            <Switch
73	              id="persistent-reservation-section"
74	              isChecked={persistentReservation}
75	              isDisabled={isLoading}
76	              onChange={(_, checked: boolean) => onChange(checked)}
77	            />
78	          </SplitItem>
79	        )}
80	      </Split>
81	      {error && (
82	        <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
83	          {error}
84	        </Alert>
85	      )}
86	    </ExpandSection>
87	  );
88	};
89	
90	export default PersistentReservationSection;

